 10	/**
 11	 * Branch 6.2 — the generic decoder.
 12	 *
 13	 * The decoder compiles a `FormDefinition` into the Effect Schema codec that
 14	 * validates its submissions, reproducing the hand-tuned contact/volunteer/
 15	 * registration validation (`contact.tsx`, `registration-schema.ts`). These tests
 16	 * pin the load-bearing guarantees the equivalence harness (Branch 6.5) will lean
 17	 * on (`prove-it-works`):
 18	 *   - each `FieldKind` decodes its valid form-input value and rejects its invalid
 19	 *     ones with a real `TranslationKey` (not a default Schema message);
 20	 *   - failures attach to the FIELD path conform renders (`formatSchemaResult`
 21	 *     buckets them by `formatPath`), so an error displays on its own field;
 22	 *   - the `checkboxBoolean` three-token codec (`true` / `false` / `on`) matches
 23	 *     `registration-schema.ts`'s `StringToBoolean`;
 24	 *   - a discriminated `variant` requires the selected branch's fields at their own
 25	 *     paths and ignores the unselected branch's;
 26	 *   - a `requiredWhenEquals` cross-field rule fires its `target` requirement only
 27	 *     when the `when` field equals a trigger value, at the target's path.
 28	 *
 29	 * Definitions are built from raw JSON (the on-bucket shape) and decoded through
 30	 * the `FormDefinition` schema first, so the decoder is exercised on the same
 31	 * branded values a real `forms/<form>.json` produces.
 32	 */
 33	
 34	const text = (en: string, fr: string) => ({ en, fr });
 35	
 36	/** Decode a raw JSON definition through the schema (as `Content.getForm` would). */
 37	const asDefinition = (json: unknown): FormDefinition =>
 38	  Schema.decodeUnknownSync(FormDefinitionSchema)(json);
 39	
 40	/** The field/form error buckets for a payload, or `null` when it decodes. */
 41	const errorsFor = (
 42	  definition: FormDefinition,
 43	  payload: unknown,
 44	): { formErrors: string[]; fieldErrors: Record<string, string[]> } | null => {
 45	  const result = decodeForm(definition, payload);
 46	  return formatSchemaResult(result) as never;
 47	};
