506	// Mirrors contact/volunteer: the `method`-gated `email`/`phone` are
507	// `optional: true` (optional-at-key, NON-EMPTY-when-present) — the oracle's
508	// `Schema.optional(Email)` where `Email` enforces `isMinLength(1)`. Two rules,
509	// like the real forms, so the "multiple unsatisfied rules surface at once" path
510	// is exercised.
511	const ruleDef = asDefinition({
512	  title: text('F', 'F'),
513	  fields: [
514	    {
515	      _tag: 'literal',
516	      name: 'method',
517	      label: text('Method', 'Méthode'),
518	      requiredMessage: 'contact.form.contact-method.required',
519	      options: [
520	        { value: 'email', label: text('Email', 'Courriel') },
521	        { value: 'phone', label: text('Phone', 'Tél') },
522	        { value: 'both', label: text('Both', 'Les deux') },
523	      ],
524	    },
525	    {
526	      _tag: 'email',
527	      name: 'email',
528	      label: text('Email', 'Courriel'),
529	      optional: true,
530	      requiredMessage: 'contact.form.email.required',
531	      invalidMessage: 'contact.form.email.error',
532	    },
533	    {
534	      _tag: 'requiredText',
535	      name: 'phone',
536	      label: text('Phone', 'Tél'),
537	      optional: true,
538	      requiredMessage: 'contact.form.phone.required',
539	    },
540	  ],
541	  rules: [
542	    {
543	      _tag: 'requiredWhenEquals',
544	      when: 'method',
545	      equals: ['email', 'both'],
546	      target: 'email',
547	      message: 'contact.form.email.required',
548	    },
549	    {
550	      _tag: 'requiredWhenEquals',
551	      when: 'method',
552	      equals: ['phone', 'both'],
553	      target: 'phone',
554	      message: 'contact.form.phone.required',
555	    },
556	  ],
557	});
558	
559	describe('requiredWhenEquals cross-field rule', () => {
560	  test('the target is required when the trigger field equals a trigger value', () => {
561	    const errors = errorsFor(ruleDef, { method: 'email' });
562	    expect(errors?.fieldErrors['email']).toEqual([
563	      'contact.form.email.required',
564	    ]);
565	  });
566	
567	  test('an empty (present-but-blank) target with the trigger active emits the required key', () => {
568	    // The oracle gates `email` as `Schema.optional(Email)`, and `Email` enforces
569	    // `isMinLength(1)`, so `{ method: 'email', email: '' }` is a decode error —
570	    // a visibly-blank required field must never decode SUCCESS. The empty present
571	    // value is rejected by the field codec (the `optional: true` email is
572	    // non-empty-when-present), surfacing exactly one error on the field.
573	    const errors = errorsFor(ruleDef, { method: 'email', email: '' });
574	    expect(errors?.fieldErrors['email']).toEqual([
575	      'contact.form.email.required',
576	    ]);
577	  });
578	
579	  test('an empty present target with the trigger INACTIVE still rejects (non-empty-when-present)', () => {
580	    // Even when `method` is `phone` (so the email rule is not triggered), a
581	    // present `email: ''` is a blank value the field codec rejects, matching the
582	    // oracle's always-on `isMinLength(1)`.
583	    const errors = errorsFor(ruleDef, { method: 'phone', email: '', phone: '5' });
584	    expect(errors?.fieldErrors['email']).toEqual([
585	      'contact.form.email.required',
586	    ]);
587	  });
588	
589	  test('two unsatisfied rules both surface (the accumulating presence filter)', () => {
590	    // `both` triggers both the email and phone rules; with neither present, BOTH
591	    // keys must fire — a chained-`.check` composition would abort after the first.
592	    const errors = errorsFor(ruleDef, { method: 'both' });
593	    expect(errors?.fieldErrors['email']).toEqual([
594	      'contact.form.email.required',
595	    ]);
596	    expect(errors?.fieldErrors['phone']).toEqual([
597	      'contact.form.phone.required',
598	    ]);
599	  });
600	
601	  test('the target is not required when the trigger field does not match', () => {
602	    expect(
603	      Result.isSuccess(decodeForm(ruleDef, { method: 'phone', phone: '5' })),
604	    ).toBe(true);
605	  });
606	
607	  test('a present target with the trigger active decodes', () => {
608	    expect(
609	      Result.isSuccess(
610	        decodeForm(ruleDef, { method: 'both', email: 'a@b.co', phone: '5' }),
611	      ),
612	    ).toBe(true);
613	  });
614	});

