 14	/**
 15	 * Branch 6.2 — the generic renderer.
 16	 *
 17	 * `<FormFields definition={def} />` renders the closed `FieldKind` set into form
 18	 * controls. These render-to-string tests pin the load-bearing behaviour the
 19	 * route migration (Branches 6.3–6.5) and the render-parity half of the
 20	 * equivalence harness (Branch 6.5) depend on (`prove-it-works`):
 21	 *   - each field kind renders a control carrying the field's submit-`name`
 22	 *     (so the browser POSTs the name the decoder addresses);
 23	 *   - bilingual `label` copy projects to the active locale (`/fr` → French);
 24	 *   - a `nestedGroup`'s inner fields render under dotted `group.field` names (the
 25	 *     shape `parseSubmission` nests for the decoder);
 26	 *   - a discriminated `variant` renders its discriminator options, and the
 27	 *     selected branch's fields render while the unselected branch's do not
 28	 *     (the client-driven conditional the hand-tuned `method` forms run).
 29	 *
 30	 * The renderer uses conform field hooks, so it is mounted inside a real
 31	 * `useForm` + `FormProvider` (a `defaultValue` selects the variant branch to
 32	 * exercise), under a router stub (`useLocale` reads `params.lang`) and a
 33	 * `LocalizationProvider`.
 34	 */
 35	
 36	const text = (en: string, fr: string) => ({ en, fr });
 37	
 38	/**
 39	 * A permissive client schema for the harness — `useForm` requires a validation
 40	 * source, but these tests exercise render output, not validation (decode is
 41	 * covered in `decode.test.ts`). An open record accepts any field shape.
 42	 */
 43	const permissiveSchema = Schema.toStandardSchemaV1(
 44	  Schema.Record(Schema.String, Schema.Unknown),
 45	);
 46	
 47	const asDefinition = (json: unknown): FormDefinition =>
 48	  Schema.decodeUnknownSync(FormDefinitionSchema)(json);
 49	
 50	/** Render `<FormFields>` for a definition, optionally in French or with a default value. */
 51	const render = (
 52	  definition: FormDefinition,
 53	  {
 54	    lang,
 55	    defaultValue,
 56	  }: { lang?: 'fr'; defaultValue?: Record<string, unknown> } = {},
 57	): string => {
 58	  function Harness() {
 59	    const { form } = useForm(permissiveSchema, {
 60	      id: 'test',
 61	      defaultValue: defaultValue ?? {},
 62	    });
 63	    return (
 64	      <FormProvider context={form.context}>
 65	        <form {...form.props}>
 66	          <FormFields definition={definition} formId={form.id} />
 67	        </form>
 68	      </FormProvider>
 69	    );
 70	  }
 71	
 72	  const Stub = createRoutesStub([
 73	    {
 74	      id: 'root',
 75	      path: ':lang?',
 76	      Component: () => (
 77	        <LocalizationProvider
 78	          translation={translations[lang === 'fr' ? 'fr' : 'en']}
 79	        >
 80	          <Harness />
 81	        </LocalizationProvider>
 82	      ),
 83	    },
 84	  ]);
 85	
 86	  return renderToString(
 87	    <Stub initialEntries={[lang === 'fr' ? '/fr' : '/']} />,
 88	  );
 89	};
